import { useEffect, useState } from "react";
import { getUsers, deleteUser } from "../api/api";
import "./users.css";
import { useNavigate } from "react-router-dom";

export default function Users() {
  const [users, setUsers] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    const data = await getUsers();

    console.log("USERS DATA:", data);

  if (data.detail) {
    alert("Session expired, login again");
    return;
    }

    setUsers(data);
  };

  const handleDelete = async (id) => {
    await deleteUser(id);
    loadUsers();
  };

  return (
    <div className="container_users" style={{ textAlign: "center", marginTop: "50px" }}>
      <h2 className="title_for_users">Users List</h2>

      {users.map((user) => (
        <div className="usersList" key={user.id} style={{ marginBottom: "10px" }}>
          {user.name} - {user.email}
          <button className="button_of_users" onClick={() => handleDelete(user.id)}>Delete</button>
          
        </div>
      ))}
    </div>
  );
}
